mapper.select:
SELECT id, user_id, cma_account_id, currency, tx_type, source_type,
       amount, balance_after, ref_type, ref_id, idempotency_key, created_at
FROM cma_transactions
WHERE user_id = #{userId}
AND tx_type = #{txType}
AND source_type = #{sourceType}
AND created_at >= #{from}
AND created_at < #{to}
ORDER BY id DESC
LIMIT #{limit} OFFSET #{offset}
